                 }
                 self.handle_input(HarnessInput::Key(key));
             }
         } else if sequence.bytes.len() > MAX_ESCAPE_SEQUENCE {
             let sequence = self
                 .escape_sequence
                 .take()
                 .expect("escape sequence is present");
             self.dispatch_pending_escape_if_needed(&sequence);
         }

         true
     }

