551	        let cursor = self.initial_visual_cursor(focus, &lines);
552	        self.mode = UiMode::Command;
553	        self.pending = None;
554	        self.visual_selection = Some(VisualSelection {
555	            focus,
556	            mode,
557	            anchor: cursor,
558	            cursor,
559	        });
