562	    fn switch_visual_selection_mode(&mut self, mode: VisualSelectionMode, right_content: &str) {
563	        let Some(selection) = self.visual_selection.as_mut() else {
564	            self.begin_visual_selection(mode, right_content);
565	            return;
566	        };
567	        selection.mode = mode;
568	        self.clamp_visual_selection(right_content);
