617	    fn clamp_visual_selection(&mut self, right_content: &str) {
618	        let Some(selection) = self.visual_selection.as_ref() else {
619	            return;
620	        };
621	        let lines = self.selection_lines(selection.focus, right_content);
622	        let max_line = lines.len().saturating_sub(1);
623	        let Some(selection) = self.visual_selection.as_mut() else {
624	            return;
625	        };
626	        selection.anchor.line = selection.anchor.line.min(max_line);
627	        selection.cursor.line = selection.cursor.line.min(max_line);
628	        for cursor in [&mut selection.anchor, &mut selection.cursor] {
629	            let max_column = lines
630	                .get(cursor.line)
631	                .map(|line| line.chars().count().saturating_sub(1))
632	                .unwrap_or_default();
633	            cursor.column = cursor.column.min(max_column);
634	        }
635	    }
