508	    fn handle_input(&mut self, input: TerminalAppInput) {
509	        match input {
510	            TerminalAppInput::Quit => {
511	                self.request_quit();
512	            }
513	            TerminalAppInput::Interrupt => {
514	                self.ui.show_ctrl_c_exit_notice();
515	                if self.ui.focus() == PaneFocus::Right
516	                    && let Some(agent_id) = self.ui.selected_agent().cloned()
517	                {
518	                    self.controller.interrupt_agent(&agent_id);
519	                    self.apply_controller_events();
520	                }
521	                self.dirty = true;
522	            }
523	            TerminalAppInput::Backspace if self.ui.mode() == UiMode::Prompt => {
524	                self.prompt_buffer.backspace();
525	                self.prompt_history_index = None;
526	                self.prompt_history_draft = None;
527	                self.dirty = true;
528	            }
529	            TerminalAppInput::Backspace if self.ui.mode() == UiMode::Insert => {
530	                self.chat_buffer.backspace();
531	                self.chat_history_index = None;
532	                self.chat_history_draft = None;
533	                self.dirty = true;
534	            }
535	            TerminalAppInput::Enter if self.ui.mode() == UiMode::Prompt => {
536	                let line = self.prompt_buffer.trimmed_string();
537	                self.prompt_buffer.clear();
538	                let actions = self.handle_ui_key(UiKey::Esc);
539	                self.record_actions(actions);
540	                if !line.is_empty() {
541	                    self.prompt_history.push(line.clone());
542	                    self.prompt_history_index = None;
543	                    self.prompt_history_draft = None;
544	                    self.handle_command_line(&line);
545	                } else {
546	                    self.prompt_history_index = None;
547	                    self.prompt_history_draft = None;
548	                }
549	                self.dirty = true;
550	            }
551	            TerminalAppInput::Enter if self.ui.mode() == UiMode::Insert => {
552	                self.send_chat_buffer();
553	            }
554	            TerminalAppInput::Char('/') if self.should_start_agent_slash_command() => {
555	                self.start_agent_slash_command();
556	                self.dirty = true;
557	            }
558	            TerminalAppInput::LineBreak if self.ui.mode() == UiMode::Insert => {
559	                self.chat_buffer.push('\n');
560	                self.chat_history_index = None;
561	                self.chat_history_draft = None;
562	                self.dirty = true;
563	            }
564	            TerminalAppInput::PasteStart => {
565	                self.paste_mode = true;
566	                self.skip_next_paste_lf = false;
567	            }
568	            TerminalAppInput::PasteEnd => {
569	                self.paste_mode = false;
570	                self.skip_next_paste_lf = false;
571	            }
572	            TerminalAppInput::Char(ch) if self.ui.mode() == UiMode::Prompt => {
573	                self.prompt_buffer.push(ch);
574	                self.prompt_history_index = None;
575	                self.prompt_history_draft = None;
576	                self.dirty = true;
577	            }
578	            TerminalAppInput::Char(ch) if self.ui.mode() == UiMode::Insert => {
579	                self.chat_buffer.push(ch);
580	                self.chat_history_index = None;
581	                self.chat_history_draft = None;
582	                self.dirty = true;
583	            }
584	            TerminalAppInput::Key(UiKey::Left) if self.ui.mode() == UiMode::Prompt => {
585	                self.prompt_buffer.move_left();
586	                self.dirty = true;
587	            }
588	            TerminalAppInput::Key(UiKey::Right) if self.ui.mode() == UiMode::Prompt => {
589	                self.prompt_buffer.move_right();
590	                self.dirty = true;
591	            }
592	            TerminalAppInput::Key(UiKey::Up) if self.ui.mode() == UiMode::Prompt => {
593	                self.recall_prompt_history(-1);
594	                self.dirty = true;
595	            }
596	            TerminalAppInput::Key(UiKey::Down) if self.ui.mode() == UiMode::Prompt => {
597	                self.recall_prompt_history(1);
598	                self.dirty = true;
599	            }
600	            TerminalAppInput::Key(UiKey::Left) if self.should_route_chat_arrow() => {
601	                self.chat_buffer.move_left();
602	                self.dirty = true;
603	            }
604	            TerminalAppInput::Key(UiKey::Right) if self.should_route_chat_arrow() => {
605	                self.chat_buffer.move_right();
606	                self.dirty = true;
607	            }
608	            TerminalAppInput::Key(UiKey::Up) if self.should_route_chat_arrow() => {
609	                self.recall_chat_history(-1);
610	                self.dirty = true;
611	            }
612	            TerminalAppInput::Key(UiKey::Down) if self.should_route_chat_arrow() => {
613	                self.recall_chat_history(1);
614	                self.dirty = true;
615	            }
616	            TerminalAppInput::Key(UiKey::Esc) => {
617	                self.prompt_buffer.clear();
618	                let actions = self.handle_ui_key(UiKey::Esc);
619	                self.record_actions(actions);
620	                self.dirty = true;
621	            }
622	            TerminalAppInput::Key(key) => {
623	                let actions = self.handle_ui_key(key);
624	                self.record_actions(actions);
625	                self.dirty = true;
626	            }
627	            TerminalAppInput::Char(ch) => {
628	                let actions = self.handle_ui_key(UiKey::Char(ch));
629	                self.record_actions(actions);
630	                self.dirty = true;
631	            }
632	            TerminalAppInput::Backspace | TerminalAppInput::Enter | TerminalAppInput::LineBreak => {
633	            }
634	        }
635	    }
