1459	fn styled_line_spans(line: &str, range: Option<(usize, usize)>) -> Spans<'static> {
1460	    let Some((start, end)) = range else {
1461	        return Spans::from(vec![Span::raw(line.to_string())]);
1462	    };
1463	    let line_len = line.chars().count();
1464	    let start = start.min(line_len);
1465	    let end = end.min(line_len);
1466	    if start >= end {
1467	        return Spans::from(vec![Span::raw(line.to_string())]);
1468	    }
1469	
1470	    let start_byte = byte_index_for_char(line, start);
1471	    let end_byte = byte_index_for_char(line, end);
1472	    let mut spans = Vec::new();
1473	    if start_byte > 0 {
1474	        spans.push(Span::raw(line[..start_byte].to_string()));
1475	    }
1476	    spans.push(Span::styled(
1477	        line[start_byte..end_byte].to_string(),
1478	        reversed_style(),
1479	    ));
1480	    if end_byte < line.len() {
1481	        spans.push(Span::raw(line[end_byte..].to_string()));
1482	    }
1483	    Spans::from(spans)
1484	}
