1486	fn selected_ranges(
1487	    lines: &[String],
1488	    selection: &VisualSelection,
1489	    force_line: bool,
1490	) -> Vec<Option<(usize, usize)>> {
1491	    let mut ranges = vec![None; lines.len()];
1492	    if lines.is_empty() {
1493	        return ranges;
1494	    }
1495	
1496	    let start_line = selection.anchor.line.min(selection.cursor.line);
1497	    let end_line = selection
1498	        .anchor
1499	        .line
1500	        .max(selection.cursor.line)
1501	        .min(lines.len() - 1);
1502	    let mode = if force_line {
1503	        VisualSelectionMode::Line
1504	    } else {
1505	        selection.mode
1506	    };
1507	
1508	    match mode {
1509	        VisualSelectionMode::Line => {
1510	            for line_index in start_line..=end_line {
1511	                ranges[line_index] = Some((0, lines[line_index].chars().count()));
1512	            }
1513	        }
1514	        VisualSelectionMode::Block => {
1515	            let start_column = selection.anchor.column.min(selection.cursor.column);
1516	            let end_column = selection.anchor.column.max(selection.cursor.column);
1517	            for line_index in start_line..=end_line {
1518	                let line_len = lines[line_index].chars().count();
1519	                let start = start_column.min(line_len);
1520	                let end = end_column.saturating_add(1).min(line_len);
1521	                ranges[line_index] = Some((start, end));
1522	            }
1523	        }
1524	        VisualSelectionMode::Character => {
1525	            let (start, end) = ordered_cursors(selection.anchor, selection.cursor);
1526	            let start_line = start.line.min(lines.len() - 1);
1527	            let end_line = end.line.min(lines.len() - 1);
1528	            if start_line == end_line {
1529	                let line_len = lines[start_line].chars().count();
1530	                ranges[start_line] = Some((
1531	                    start.column.min(line_len),
1532	                    end.column.saturating_add(1).min(line_len),
1533	                ));
1534	            } else {
1535	                for line_index in start_line..=end_line {
1536	                    let line_len = lines[line_index].chars().count();
1537	                    ranges[line_index] = if line_index == start_line {
1538	                        Some((start.column.min(line_len), line_len))
1539	                    } else if line_index == end_line {
1540	                        Some((0, end.column.saturating_add(1).min(line_len)))
1541	                    } else {
1542	                        Some((0, line_len))
1543	                    };
1544	                }
1545	            }
1546	        }
1547	    }
1548	
1549	    ranges
1550	}
1551	
1552	fn selected_text(lines: &[String], selection: &VisualSelection, force_line: bool) -> String {
1553	    let ranges = selected_ranges(lines, selection, force_line);
1554	    ranges
1555	        .into_iter()
1556	        .enumerate()
1557	        .filter_map(|(index, range)| {
1558	            range.map(|(start, end)| slice_chars(&lines[index], start, end))
1559	        })
1560	        .collect::<Vec<_>>()
1561	        .join("\n")
1562	}

